external_knowledge:
; Server configurations include server name, IP address, data center ID, status, OS type, model, CPU cores, memory size, disk size, and last reboot time; 
; Performance metrics include CPU usage, memory usage, network traffic, disk I/O, and predictive analytics data such as predicted issues, probabilities, recommended actions, and confidence intervals;
; Alert information encompasses alert ID, timestamp, description, severity, handling status, type, source, and actions taken.

sql:
SELECT AVG(avg_memory_usage) AS average_memory_usage
FROM memory_metrics
WHERE server_id = 1;

SELECT AVG(avg_cpu_usage) AS average_cpu_usage
FROM cpu_metrics
WHERE server_id = 1;

SELECT server_name, last_reboot
FROM servers
ORDER BY server_name;

external_knowledge:
; Heavily loaded refers to high average maximum CPU usage (> 80%); 
; The last week refers to the past 7 days; 
; Active servers are those that are currently operational and not under maintenance.

sql:
SELECT MAX(timestamp)
  FROM alerts
  WHERE server_id = 1;

SELECT server_id, AVG(avg_memory_usage) AS average_memory_usage
FROM memory_metrics
GROUP BY server_id;

SELECT avg_memory_usage, max_memory_usage
FROM memory_metrics
WHERE server_id = 0;
